399 static void computeKnownBitsMul(const Value *Op0, const Value *Op1, bool NSW,
400                                 const APInt &DemandedElts, KnownBits &Known,
401                                 KnownBits &Known2, unsigned Depth,
402                                 const SimplifyQuery &Q) {
403   computeKnownBits(Op1, DemandedElts, Known, Depth + 1, Q);
404   computeKnownBits(Op0, DemandedElts, Known2, Depth + 1, Q);
405 
406   bool isKnownNegative = false;
407   bool isKnownNonNegative = false;
408   // If the multiplication is known not to overflow, compute the sign bit.
409   if (NSW) {
410     if (Op0 == Op1) {
411       // The product of a number with itself is non-negative.
412       isKnownNonNegative = true;
413     } else {
414       bool isKnownNonNegativeOp1 = Known.isNonNegative();
415       bool isKnownNonNegativeOp0 = Known2.isNonNegative();
416       bool isKnownNegativeOp1 = Known.isNegative();
417       bool isKnownNegativeOp0 = Known2.isNegative();
418       // The product of two numbers with the same sign is non-negative.
419       isKnownNonNegative = (isKnownNegativeOp1 && isKnownNegativeOp0) ||
420                            (isKnownNonNegativeOp1 && isKnownNonNegativeOp0);
421       // The product of a negative number and a non-negative number is either
422       // negative or zero.
423       if (!isKnownNonNegative)
424         isKnownNegative =
425             (isKnownNegativeOp1 && isKnownNonNegativeOp0 &&
426              Known2.isNonZero()) ||
427             (isKnownNegativeOp0 && isKnownNonNegativeOp1 && Known.isNonZero());
428     }
429   }
430 
431   bool SelfMultiply = Op0 == Op1;
432   // TODO: SelfMultiply can be poison, but not undef.
433   if (SelfMultiply)
434     SelfMultiply &=
435         isGuaranteedNotToBeUndefOrPoison(Op0, Q.AC, Q.CxtI, Q.DT, Depth + 1);
436   Known = KnownBits::mul(Known, Known2, SelfMultiply);
437 
438   // Only make use of no-wrap flags if we failed to compute the sign bit
439   // directly.  This matters if the multiplication always overflows, in
440   // which case we prefer to follow the result of the direct computation,
441   // though as the program is invoking undefined behaviour we can choose
442   // whatever we like here.
443   if (isKnownNonNegative && !Known.isNegative())
444     Known.makeNonNegative();
445   else if (isKnownNegative && !Known.isNonNegative())
446     Known.makeNegative();
447 }
