449 void llvm::computeKnownBitsFromRangeMetadata(const MDNode &Ranges,
450                                              KnownBits &Known) {
451   unsigned BitWidth = Known.getBitWidth();
452   unsigned NumRanges = Ranges.getNumOperands() / 2;
453   assert(NumRanges >= 1);
454 
455   Known.Zero.setAllBits();
456   Known.One.setAllBits();
457 
458   for (unsigned i = 0; i < NumRanges; ++i) {
459     ConstantInt *Lower =
460         mdconst::extract<ConstantInt>(Ranges.getOperand(2 * i + 0));
461     ConstantInt *Upper =
462         mdconst::extract<ConstantInt>(Ranges.getOperand(2 * i + 1));
463     ConstantRange Range(Lower->getValue(), Upper->getValue());
464 
465     // The first CommonPrefixBits of all values in Range are equal.
466     unsigned CommonPrefixBits =
467         (Range.getUnsignedMax() ^ Range.getUnsignedMin()).countl_zero();
468     APInt Mask = APInt::getHighBitsSet(BitWidth, CommonPrefixBits);
469     APInt UnsignedMax = Range.getUnsignedMax().zextOrTrunc(BitWidth);
470     Known.One &= UnsignedMax & Mask;
471     Known.Zero &= ~UnsignedMax & Mask;
472   }
473 }
