475 static bool isEphemeralValueOf(const Instruction *I, const Value *E) {
476   SmallVector<const Value *, 16> WorkSet(1, I);
477   SmallPtrSet<const Value *, 32> Visited;
478   SmallPtrSet<const Value *, 16> EphValues;
479 
480   // The instruction defining an assumption's condition itself is always
481   // considered ephemeral to that assumption (even if it has other
482   // non-ephemeral users). See r246696's test case for an example.
483   if (is_contained(I->operands(), E))
484     return true;
485 
486   while (!WorkSet.empty()) {
487     const Value *V = WorkSet.pop_back_val();
488     if (!Visited.insert(V).second)
489       continue;
490 
491     // If all uses of this value are ephemeral, then so is this value.
492     if (llvm::all_of(V->users(), [&](const User *U) {
493                                    return EphValues.count(U);
494                                  })) {
495       if (V == E)
496         return true;
497 
498       if (V == I || (isa<Instruction>(V) &&
499                      !cast<Instruction>(V)->mayHaveSideEffects() &&
500                      !cast<Instruction>(V)->isTerminator())) {
501        EphValues.insert(V);
502        if (const User *U = dyn_cast<User>(V))
503          append_range(WorkSet, U->operands());
504       }
505     }
506   }
507 
508   return false;
509 }
